	`orgId` int NOT NULL,
	`phoneNormalized` varchar(20) NOT NULL,
	`areaCode` varchar(3),
	`uploadedAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `dnc_numbers_id` PRIMARY KEY(`id`)
);
ALTER TABLE `leads` ADD `dncFlagged` boolean DEFAULT false NOT NULL;
